parameters.jsCode:
const input = $json.body || $json;

const url = input.repoUrl;

const match = url.match(/github\.com\/([^\/]+)\/([^\/]+)/);

if (!match) {
  throw new Error("Invalid GitHub URL");
}

return {
  owner: match[1],
  repo: match[2],
};

const tree = $json.tree;

const importantExtensions = [
  '.js', '.ts', '.jsx', '.tsx',
  '.py', '.java', '.go',
  '.rs', '.php', '.cpp',
  '.c', '.h', '.hpp',
  '.cs', '.rb'
];

const importantFiles = [
  // 'package.json',
  'requirements.txt',
  // 'Dockerfile',
  // 'docker-compose.yml'
];

const ignoredFolders = [
  'node_modules',
  'dist',
  'build',
  '.git',
  'coverage',
  '__pycache__'
];

const filtered = tree.filter(file => {
  const path = file.path;

  if (file.type !== 'blob') return false;

  if (ignoredFolders.some(folder => path.includes(folder))) {
    return false;
  }

  if (importantFiles.some(name => path.endsWith(name))) {
    return true;
  }

  if (importantExtensions.some(ext => path.endsWith(ext))) {
    return true;
  }

  return false;
});

return {
  importantFiles: filtered.slice(0, 20)
};

const importantFiles = $json.importantFiles;

const owner = $('HTTP Request1').first().json.owner.login;
const repo = $('HTTP Request1').first().json.name;
const branch = $('HTTP Request1').first().json.default_branch;

return importantFiles.map(file => ({
  json: {
    owner,
    repo,
    path: file.path,
    branch
  }
}));

const decoded = Buffer
  .from($json.content || '', 'base64')
  .toString('utf-8');

const previous = $('Code in JavaScript2').item.json;

return {
  owner: previous.owner,
  repo: previous.repo,
  branch: previous.branch,
  path: previous.path,

  content: decoded.slice(0, 1500)
};

