SUMMARY:
${item.json.response}
`;
}).join('\n\n-------------------\n\n');

const first = items[0].json;

return [
  {
    json: {
      owner: first.owner,
      repo: first.repo,
      repositoryAnalysis: combined
    }
  }
];

const original = $json;

// Get repo metadata from the flatten node
const metadata = $('Code in JavaScript2').item.json;

return {
  owner: metadata.owner,
  repo: metadata.repo,
  branch: metadata.branch,
  ...original
};

const repo = $json.repo;
const owner = $json.owner;

// Ollama response
const generated = $json.response || '';

// Remove any wrong/generated title
const cleaned = generated.replace(/^# .*\n/, '');

const finalReadme = `# ${repo}

> Repository: https://github.com/${owner}/${repo}

${cleaned}`;

return {
  owner,
  repo,
  readme: finalReadme
};

